#include <iostream>
using namespace std;

class Box {
private:
 int width;
 int height;
public:
 Box(int w, int h) : width(w), height(h) {}
 friend class Rectangle; // Rectangle is friend of Box
};

class Rectangle {
public:
 void displayDimensions(Box& b) {
 cout << "Width: " << b.width << endl;
 cout << "Height: " << b.height << endl;
 }
 int calculateArea(Box& b) {
 return b.width * b.height;
 }
};

int main() {
 Box b(10, 5);
 Rectangle r;
 r.displayDimensions(b);
 cout << "Area: " << r.calculateArea(b) << endl;
 return 0;
}

#include <iostream>
using namespace std;

class A {
private:
 int data = 100;
 friend class B; // B is friend of A
public:
 void showBData(class B& b); // Forward declaration
};

class B {
private:
 int info = 50;
public:
 void accessA(A& a) {
 cout << "B accessing A's private data: " << a.data << endl;
 }
};

void A::showBData(B& b) {
 // This would cause error - A cannot access B's private
 // cout << b.info; // Error!
 cout << "A cannot access B's private info" << endl;
}

int main() {
 A a;
 B b;
 b.accessA(a); // Works - B accesses A
 a.showBData(b); // A cannot access B's private
 return 0;
}

#include <iostream>
using namespace std;

class A {
private:
 int secret = 999;
 friend class B; // Only B is friend
};

class B {
public:
 void accessA(A& a) {
 cout << "B can access A's secret: " << a.secret << endl;
 }
};

class DerivedB : public B {
public:
 void tryAccessA(A& a) {
 // Error: DerivedB cannot access A's private
 // cout << a.secret; // Would cause error!
 cout << "DerivedB cannot access A's private secret" << endl;
 }
};

int main() {
 A a;
 B b;
 DerivedB db;

 b.accessA(a); // Works
 db.tryAccessA(a); // Does not work - friendship not inherited
 return 0;
}

#include <iostream>
using namespace std;

class Transaction; // Forward declaration

class BankAccount {
private:
 double balance;
 string accountNumber;

public:
 BankAccount(string accNo, double initialBalance) 
 : accountNumber(accNo), balance(initialBalance) {}

 friend class Transaction; // Transaction can access private members

 void displayBalance() const {
 cout << "Account: " << accountNo << ", Balance: Rs." << balance << endl;
 }
};

class Transaction {
public:
 void deposit(BankAccount& acc, double amount) {
 if (amount > 0) {
 acc.balance += amount;
 cout << "Deposited Rs." << amount << endl;
 }
 }

 void withdraw(BankAccount& acc, double amount) {
 if (amount > 0 && amount <= acc.balance) {
 acc.balance -= amount;
 cout << "Withdrew Rs." << amount << endl;
 } else {
 cout << "Insufficient balance or invalid amount" << endl;
 }
 }

 void transfer(BankAccount& from, BankAccount& to, double amount) {
 if (amount > 0 && amount <= from.balance) {
 from.balance -= amount;
 to.balance += amount;
 cout << "Transferred Rs." << amount << endl;
 }
 }
};

int main() {
 BankAccount acc1("ACC001", 10000);
 BankAccount acc2("ACC002", 5000);
 Transaction txn;

 acc1.displayBalance();
 txn.deposit(acc1, 5000);
 txn.withdraw(acc1, 3000);
 acc1.displayBalance();

 txn.transfer(acc1, acc2, 2000);
 acc1.displayBalance();
 acc2.displayBalance();

 return 0;
}

#include <iostream>
using namespace std;

class A {
public:
 friend class B; // Works in public section
};

class C {
protected:
 friend class D; // Works in protected section
};

class E {
private:
 friend class F; // Works in private section
};

class B {
public:
 void show() { cout << "B can access A's members" << endl; }
};

class D {
public:
 void show() { cout << "D can access C's members" << endl; }
};

class F {
public:
 void show() { cout << "F can access E's members" << endl; }
};

int main() {
 B b; b.show();
 D d; d.show();
 F f; f.show();
 cout << "All three work regardless of section" << endl;
 return 0;
}
